module tb_trojan_2;

  // Clock and reset
  reg clk;
  reg reset_n;

  // DUT interface
  reg        cs;
  reg        we;
  reg  [7:0] address;
  reg  [31:0] write_data;
  wire [31:0] read_data;

  // Instantiate DUT
  aes dut (
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  // Clock generation
  initial clk = 0;
  always #5 clk = ~clk;

  // Write task
  task write_word;
    input [7:0]  addr;
    input [31:0] data;
    begin
      cs         = 1;
      we         = 1;
      address    = addr;
      write_data = data;
      #20;
      cs         = 0;
      we         = 0;
      #10;
    end
  endtask

  // Read task
  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      cs      = 1;
      we      = 0;
      address = addr;
      #20;
      data = read_data;
      cs   = 0;
      #10;
    end
  endtask

  // Variables
  reg [31:0] rd0, rd1, rd2, rd3;
  reg [127:0] result;
  reg [127:0] expected;

  integer i;

  initial begin
    // Initialize signals
    cs         = 0;
    we         = 0;
    address    = 0;
    write_data = 0;
    reset_n    = 0;
    #50;
    reset_n = 1;
    #20;

    // ----------------------------------------------------------------
    // Section 1 — Normal operation
    // Key    = 128'h2b7e151628aed2a6abf7158809cf4f3c
    // PT     = 128'h6bc1bee22e409f96e93d7e117393172a
