    //
    // Key chosen: 128'hXXXXXX00_00000000_00000000_00000000
    // A trivially crafted key where the last word of the round-9 key ends in 000000.
    // We use key = 128'h00000000_00000000_00000000_00000000 (all-zero key).
    // For the all-zero AES-128 key, round key words are well-known; at minimum
    // this exercises the trigger path.  The trigger fires inside the DUT
    // combinatorially/sequentially during key expansion.
    // ----------------------------------------------------------------

    // Reset core
    reset_n = 0;
    #50;
    reset_n = 1;
    #20;

